var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"와아, 크리스마스에 시내를 나와보는 건 처음이예요.","JPN":"わあ、クリスマスに市街地に出るのは初めてです。","ENG":"Wow, it's my first time being downtown during Christmas.","TWN":"哇～我第一次在聖誕節來市區呢！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그렇지? 가게를 하루 쉬는 보람이 있네.","JPN":"でしょう？　お店、一日営業中止にした甲斐があるわ。","ENG":"Right? It was worth taking a day off from the bar.","TWN":"對吧？店休一天果然值得。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"트리장식들도 예쁘고, 평소보다 사람들이 엄청 많네요.","JPN":"ツリーのオーナメントも綺麗だし、いつもより人もたくさんいますね。","ENG":"The tree decorations are so pretty, and there seems to be more people out than usual.","TWN":"聖誕樹裝飾好漂亮，人也比平常多好多。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…응?","JPN":"……ん？","ENG":"...Hmm?","TWN":"……嗯？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COUPLE_EXTRA_NULL_NULL","text":{"KOREA":"사랑해, 자기.","JPN":"愛してるよ、ダーリン。","ENG":"I love you, babe.","TWN":"我愛你，親愛的。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COUPLE_EXTRA_NULL_NULL","text":{"KOREA":"자기 손 따뜻하다.","JPN":"手、暖かいね。","ENG":"Your hands are so warm.","TWN":"你的手好溫暖。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COUPLE_EXTRA_NULL_NULL","text":{"KOREA":"자기가 준 목도리도 엄청 따뜻해.","JPN":"マフラーもとても暖かいよ。","ENG":"The muffler you gave is also so warm.","TWN":"你送的圍巾也超暖的。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"우와아…….","JPN":"うわあ……","ENG":"Whoa...","TWN":"哇啊……"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜이여. 뭘 그리 멀뚱히 보고 있느냐?","JPN":"ニコルよ。何をそんなにじっと見ているのか？","ENG":"Nicole, what are you staring at?","TWN":"妮可啊，你在發什麼呆？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아앗?! 모모는 보면 안 돼요!","JPN":"ああっ！？　モモは見ちゃダメです！","ENG":"H-huh?! No, Momo! Cover your eyes!","TWN":"啊？！莫莫不可以看！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"무, 무엄하도다! 감히 이 몸의 두 눈을 손으로 봉인하다니!","JPN":"け、けしからん！　吾輩の目を両手で封印するとは！","ENG":"H-how dare you! How dare you use your hands to seal my vision!","TWN":"放、放肆！竟敢用手遮住我的眼睛！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"왜 그래?","JPN":"どうしたの？","ENG":"What's wrong?","TWN":"怎麼了？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨. 여긴 위험해요. 남녀가 공공장소에서 아무렇지 않게 저런 짓을 벌이고 있다고요.","JPN":"グレモリーさん、ここは危険です。男女が公共の場で平気にあんなことしてるんですよ。","ENG":"Gremory, this place is dangerous. Couples are out in public casually showing affection like it's nothing.","TWN":"葛茉莉小姐，這裡很危險！居然有男女在公共場所做那種事！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"…커플끼리 손잡고 안는 거 말이야?","JPN":"……カップルが手を繋いで抱きあってること？","ENG":"...You mean couples holding hands and hugging each other?","TWN":"……你是說情侶牽手、擁抱？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇죠? 파렴치하잖아요. 모모가 보기라도 했다간 분명 교육에 좋지 않을 거라고요.","JPN":"そうですよね？　破廉恥じゃないですか。モモが見たらきっと教育上よくないんです。","ENG":"You see it too, right? It's outrageous. If Momo sees it, it won't be good for her education.","TWN":"對啊？很不檢點耶？要是被莫莫看到，一定會教壞她！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"어? 그레모리… 씨? 왜 저한테 갑자기 포옹을…?","JPN":"あれ？　グレモリー……さん？　どうしていきなり私を抱いて……？","ENG":"Huh? Gremory...? Why are you suddenly hugging me...?","TWN":"欸？葛茉莉……小姐？你怎麼突然抱住我……？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어때? 추운 겨울날 이렇게 붙어있으니 따뜻하지? 다들 그런 이유로 안고 있는 거니까 너무 신경 안 써도 돼.","JPN":"どう？　少しは冬の寒さが和らぐでしょう？　みんな、そういう理由で抱きしめてあげてるのよ。だからあまり気にしなくていいわ。","ENG":"How is it? Isn't it warm to be so close together on a cold day like this? They're all close for the same reason, so don't worry about it.","TWN":"怎麼樣？冬天這樣貼在一起不是很溫暖嗎？大家都是因為這個理由才抱在一起，不用太在意。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그… 그런 걸까요? 하긴 올겨울은 전례 없는 강추위라고 했으니…","JPN":"そ……そうなんでしょうか？　まあ、今年の冬は前例のない寒さだと言っていましたし……","ENG":"Do... do you really think so? But then again, they did say this winter was going to be the coldest ever...","TWN":"是……是這樣嗎？今年冬天確實說有史無前例的寒流……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"하수인들아. 그렇게 앞뒤로 붙어 있으면 이 몸의 숨이 막히는 것이다.","JPN":"下僕たちよ。そうやって前後からくっついていると、吾輩は息ができないのだ。","ENG":"Subjects! If you two stick to me like that, I can't breathe.","TWN":"手下們，你們前後夾著我，我都快喘不過氣了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"아아, 저 커플 키스하려나 보네에-","JPN":"ああ～あのカップル、キスしそう～","ENG":"Oh, look. That couple is about to kiss.","TWN":"啊啊，那對情侶是不是要接吻了—"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"흐아아, 왜, 저 분들, 신성한 날, 길거리, 저런, 파렴치, 행위를…?!","JPN":"ふああ、どうして、あの方たち、この神聖なる日に、道、あんな、破廉恥、ことを……！？","ENG":"Hyaagh, why, shamelessly, on such, a sacred day, would they, act so, on the streets...?!","TWN":"嗚哇啊！為、為什麼那些人，在這麼神聖的日子、在大街上、會做出、那種、不知羞恥、的行為……？！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"언어체계가 망가질 정도로 충격 받은 거야?","JPN":"まともに話せなくなるほどショックだったのかしら。","ENG":"Are you so shocked that you lost the ability to speak?","TWN":"你是衝擊大到語言系統都壞掉了嗎？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"키스씬이라면 드라마랑 만화에 자주 봤잖아?","JPN":"キスならドラマとマンガでよく見たでしょう。","ENG":"But you've seen a lot of kissing in TV shows and comics, haven't you?","TWN":"電視劇和漫畫裡不也常看到接吻的場面？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그건 현실이 아닌 걸요! 심지어 저 사람들 부부도 아닌 것 같은데!","JPN":"それは現実じゃないでしょう！　しかもあの人たち、夫婦でもないみたいですし！","ENG":"But those aren't in real life! And I don't think those two are even married!","TWN":"那是虛構的啊！而且他們看起來也不像夫妻！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 크리스마스엔 저러는 게 흔한 일인 걸?","JPN":"でも、クリスマスにあんなことは別に珍しくないわよ？","ENG":"But it's common to see people kissing in Christmas.","TWN":"但聖誕節的這種事很常見吧？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…경찰에 신고하는 게 좋을까요? 공연음란죄라던가…!","JPN":"……警察に通報した方がいいんでしょうか？　公然わいせつ罪とか……！","ENG":"...Should I call the cops on them for public indecency...?!","TWN":"……要不要報警？說他們公然猥褻之類的……！"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"벌거벗고 있는 것도 아닌데 저 정도는 익숙해지는 편이 좋아. 명절마다 가게에 틀어박혀 있고 싶지 않다면 말이지.","JPN":"裸になってるわけじゃないし、あのくらいは慣れた方がいいわ。祝日にお店に引きこもっていたくないならね。","ENG":"It's not like they're naked out in public, so you should get used to seeing it. Unless you want to be stuck working at the bar every holiday.","TWN":"他們又沒脫光，這種程度你還是學著習慣比較好。不然每到節日你就只能一直關在店裡了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으으… 저런 불경함에 익숙해지라니, 저에겐 무리라고요.","JPN":"うう……あんな不敬なことに慣れろって、私には無理なんです。","ENG":"Ngh... It's going to be difficult for me to get used to such blasphemous acts.","TWN":"嗚嗚……要我習慣這種褻瀆的行為，對我來說太勉強了啦。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그나저나 서둘러야 하지 않겠어? 곧 오프라인 한정판매가 시작될 텐데.","JPN":"それより、急がなくて大丈夫？　もうすぐオフラインの限定販売が始まるわよ。","ENG":"Anyway, shouldn't we hurry? The offline limited sales are starting soon.","TWN":"話說回來，我們不該快點嗎？線下限定販售就快開始了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"늦으면 줄만 서다가 집에 가게 될 걸?","JPN":"遅れると何も買えなくなるわね。","ENG":"If we're late, all we'll be doing is waiting in line and going home with nothing.","TWN":"再晚一點，可能只剩排隊排到回家喔？"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"앗, 벌써 오픈 시간이 코앞으로?!","JPN":"あっ、もうイベントの時間が！？","ENG":"Oh! It's already opening time?!","TWN":"啊！已經快到開賣時間了？！"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};